const Q_BIOLOGY_2009=[{"id": "objective>Biology>2009>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the level of organization of an onion bulb?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tissue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Organ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Systemic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Organismal</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An onion bulb is an organ. In biology, an organ is a group of tissues that perform a specific function or group of functions. In the case of an onion bulb, it is a storage organ that stores nutrients for the plant.</div>", "topic": "LIVING ORGANISMS : LEVEL OF ORGANIZATION"}, {"id": "objective>Biology>2009>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A characteristic exhibited by all living organisms is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sexual reproduction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aerobic respiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the ability to move from one place to another</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the ability to remove unwanted substances </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">All living organisms have the ability to remove unwanted substances, which is a process known as excretion. This corresponds to option 4. The other options are incorrect because not all organisms reproduce sexually, not all organisms respire aerobically, and not all organisms have the ability to move from one place to another.</div>", "topic": "LIVING ORGANISMS : CHARACTERISTICS"}, {"id": "objective>Biology>2009>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a cell, the genes are carried by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nuclear membranes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chromatin threads</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lysosomes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mitochondria</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a cell, genes are carried by chromatin threads. Chromatin is a complex of DNA and protein found in eukaryotic cells. Its primary function is packaging long DNA molecules into more compact, denser structures. This prevents the strands from becoming tangled and also plays important roles in reinforcing the DNA during cell division, preventing DNA damage, and regulating gene expression and DNA replication.</div>", "topic": "HEREDITY : CHROMOSOMES"}, {"id": "objective>Biology>2009>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Alternation of asexual and sexual mode of reproduction is found in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">blue-green algae</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Euglena</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fern</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Maize </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Alternation of asexual and sexual mode of reproduction is found in Ferns. This is known as alternation of generations. In this type of life cycle, the organism alternates between a sexual phase or generation, called the gametophyte, and an asexual phase or generation, called the sporophyte. In ferns, the sporophyte is the large plant that we usually think of as a fern, while the gametophyte is a small, heart-shaped plant that is rarely noticed.</div>", "topic": "REPRODUCTION : ASEXUAL REPRODUCTION~~REPRODUCTION : SEXUAL REPRODUCTION"}, {"id": "objective>Biology>2009>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The first terrestrial vertebrates evolved from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Pisces</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reptilia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Amphibia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mammalia</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The first terrestrial vertebrates evolved from Pisces (fish). This is based on the theory of evolution which suggests that the first terrestrial vertebrates were a group of fishes that developed legs from their fins and lungs from their swim bladders, allowing them to survive on land. These evolved fishes are known as amphibians, which are considered to be the first terrestrial vertebrates.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>2009>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In plants, the structures that play roles similar to the arteries and veins of animals are the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">xylem and phloem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">root hairs and xylem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lenticels and phloem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">roots and stems </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In plants, xylem and phloem play roles similar to the arteries and veins of animals. Xylem is responsible for the transport of water and dissolved minerals absorbed from the soil to all parts of the plant. This is similar to the function of arteries in animals, which transport oxygenated blood from the heart to the rest of the body. Phloem, on the other hand, transports food substances that are prepared by the leaves to all parts of the plant. This is similar to the function of veins in animals, which carry deoxygenated blood and nutrients from the body back to the heart.</div>", "topic": "TRANSPORT : PLANT VASCULAR SYSTEM"}, {"id": "objective>Biology>2009>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A blue-green alga is not a protophyte because </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it is aquatic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">its cell are prokaryotic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it cannot move</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it is not a green plant</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A blue-green alga is not a protophyte because its cells are prokaryotic. Protophytes are a group of organisms that are considered to be the earliest forms of plants, and they are eukaryotic, meaning their cells have a true nucleus. Blue-green algae, on the other hand, are prokaryotic, meaning their cells do not have a true nucleus. This is the main reason why blue-green algae are not considered protophytes.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : PROTISTA"}, {"id": "objective>Biology>2009>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The structure labelled <strong>X</strong> is for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">attachment </div>", "<div style=\"font-family:Cambria;font-size:17px;\">feeding </div>", "<div style=\"font-family:Cambria;font-size:17px;\">seeing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">breathing</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is for attachment, The presence of hooks and suckers helps them the fasten themselves to the wall of the intestine </div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : LEAF"}, {"id": "objective>Biology>2009>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The habitat of the organism is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">slow moving streams and marshes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the stomach of large mammals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">under leaf litter on forest floor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the small intestine of large vertebrates</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is the the small intestine of large vertebrates.It lives in the small intestine of large vertebrates where they get their nutrient from. </div>", "topic": "NATURAL HABITAT : AQUATIC TERRESTRIAL AND ARBOREAL"}, {"id": "objective>Biology>2009>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The feature that makes locomotion in water easy for fish is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">scaly body </div>", "<div style=\"font-family:Cambria;font-size:17px;\">slimy body</div>", "<div style=\"font-family:Cambria;font-size:17px;\">streamlined body</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lateral body</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The feature that makes locomotion in water easy for fish is the streamlined body. A streamlined body reduces the resistance to motion through a fluid such as water. This allows fish to move quickly and efficiently through water. The other options, such as a scaly body, slimy body, or lateral body, do not primarily contribute to ease of locomotion in water.</div>", "topic": "STRUCTURAL/BEHAVIOURAL ADAPTATIONS OF VERTEBRATES : BONY FISH"}, {"id": "objective>Biology>2009>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Bird toes suitable for digging have claws that are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">blunt </div>", "<div style=\"font-family:Cambria;font-size:17px;\">curved</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hooked</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sharp</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bird toes suitable for digging have claws that are blunt. Fowls have blunt and strong claws on their toes for scratching.</div>", "topic": "STRUCTURAL/BEHAVIOURAL ADAPTATIONS OF VERTEBRATES : BIRD"}, {"id": "objective>Biology>2009>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Chewing the cud is an adaptation peculiar to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">herbivores</div>", "<div style=\"font-family:Cambria;font-size:17px;\">omnivores</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rodents</div>", "<div style=\"font-family:Cambria;font-size:17px;\">non-ruminants</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chewing the cud is an adaptation peculiar to herbivores. This process, also known as rumination, involves the regurgitation of food from the rumen (a part of the stomach) back to the mouth for further chewing. This helps in the breakdown of plant materials, making it easier for digestion and absorption of nutrients.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2009>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The structure that controls loss of water vapour during transpiration is labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Transpiration takes place when the stomata opens due to turgidity guard cells closes due to flaccidity.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : LEAF"}, {"id": "objective>Biology>2009>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The part labelled <strong>I</strong> is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">spongy mesophyll</div>", "<div style=\"font-family:Cambria;font-size:17px;\">upper epidermis </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cuticle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vein</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is the cuticle.The cuticle lines the outer part of the leaf. </div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : LEAF"}, {"id": "objective>Biology>2009>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an example of a carnivorous plant?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Hydra</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bladderwort</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Yeast</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Spirogyra</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Carnivorous plants are plants that derive some or most of their nutrients from trapping and consuming animals or protozoans, typically insects and other arthropods. Bladderwort is a type of carnivorous plant that traps small organisms—often water fleas—in bladder-like structures and digests them. Therefore, the correct answer is 'Bladderwort'.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2009>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> Emulsification of fats takes place in the part labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Emulsification of fats takes place in the part labelled IV which is the duodenum. The duodenum contains pancreas which secretes pancreatic juice that contains three enzymes(Amylase, lipase and trypsin). Lipase converts fats and oil to fatty acids and glycerol. The digestion of fats and oil is aided by bile which is secreted by the liver and stored in the gall bladder. </div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2009>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The content of the part labelled <strong>III</strong> is usually </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">neutral</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkaline</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acidic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">saline</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is acidic, the part labelled III is the stomach, it produces the gastric juice which secretes HCl which is acidic</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2009>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The part of the alimentary system of a bird where food is ground into small particles is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cloaca </div>", "<div style=\"font-family:Cambria;font-size:17px;\">stomach</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crop</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gizzard</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In birds, the gizzard is the part of the alimentary system where food is ground into small particles. The gizzard is a muscular part of a bird's stomach that uses grit (small stones swallowed by the bird) to grind grains and hard food into smaller, digestible particles.</div>", "topic": "STRUCTURAL/BEHAVIOURAL ADAPTATIONS OF VERTEBRATES : BIRD"}, {"id": "objective>Biology>2009>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following describes the sequence of blood flow from the heart to a tissue?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Heart → artery → arteriole → tissue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Heart → vein → venule → tissue </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Heart → venule → vein → tissue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Heart → arteriole → artery → tissue </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sequence of blood flow from the heart to a tissue is: Heart → artery → arteriole → tissue. The heart pumps oxygenated blood to the body through arteries. These arteries branch into smaller vessels called arterioles, which further branch into even smaller capillaries that supply oxygen and nutrients to the tissues.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2009>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The enzymes of the glycolytic pathway are located in the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mitochondria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gastric juice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plasma</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cytoplasm</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The enzymes of the glycolytic pathway are located in the cytoplasm. Glycolysis is the metabolic pathway that converts glucose into pyruvate. The free energy released in this process is used to form the high-energy molecules ATP (adenosine triphosphate) and NADH (reduced nicotinamide adenine dinucleotide).</div>", "topic": "RESPIRATION : AEROBIC RESPIRATION"}, {"id": "objective>Biology>2009>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In insects, the structure that performs the same function as the kidney in man is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nephridium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">flame cell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Malpighian tubule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trachea</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In insects, the Malpighian tubule system serves as the excretory and osmoregulatory system, similar to the function of kidneys in humans. The Malpighian tubules work by filtering out waste products from the insect's hemolymph (a fluid equivalent to blood) and then excreting the waste as solid uric acid. This is similar to how kidneys filter out waste products from the blood in humans.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2009>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The axial skeleton is found in the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">skull, ribs, vertebral column and breast bone </div>", "<div style=\"font-family:Cambria;font-size:17px;\">skull, humerus, vertebral column and ribs </div>", "<div style=\"font-family:Cambria;font-size:17px;\">breastbone, clavicle, ribs and vertebral column</div>", "<div style=\"font-family:Cambria;font-size:17px;\">femur, sternum, ulna and skull</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The axial skeleton is the part of the skeleton that consists of the bones of the head and trunk of a vertebrate. In the human skeleton, it consists of 80 bones and is composed of six parts; the skull bones, the ossicles of the middle ear, the hyoid bone, the rib cage, sternum and the vertebral column.</div>", "topic": "SUPPORT AND MOVEMENT : TYPES AND FUNCTIONS OF THE SKELETON"}, {"id": "objective>Biology>2009>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The male sex cells are contained in the part labelled </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">II - The part labelled  III is the anther which is part of the male sex cell.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2009>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The likely pollinating agent of the flower is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wind</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">insect </div>", "<div style=\"font-family:Cambria;font-size:17px;\">man</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Insect, The likely pollinated agent because it has large conspicuous and the petals are shaped and arranged to enable visiting insect to become dusted with pollen grains </div>", "topic": "REPRODUCTION : SEXUAL REPRODUCTION"}, {"id": "objective>Biology>2009>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The reproductive system of a male mammal is made up of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">claspers, prostrate gland, sperm duct and vas deferens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">testis, prostrate gland, sperm duct and vas deferens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oviduct, urethra, testis and sperm duct</div>", "<div style=\"font-family:Cambria;font-size:17px;\">testis, uterus, prostrate gland and sperm duct</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The male reproductive system of mammals is made up of several components, including the testes (which produce sperm), the prostate gland (which produces a fluid that nourishes and transports sperm), the sperm duct or vas deferens (which carry sperm from the testes to the urethra), and the penis (which delivers sperm into the female reproductive tract).</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2009>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a bean seed, absorption of water at the beginning of germination is through the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hilum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">micropyle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">testa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plumule</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a bean seed, absorption of water at the beginning of germination is through the micropyle. The micropyle is a small opening in the surface of an ovule, through which the pollen tube penetrates, often visible as a small pore in the ripe seed. It allows the entry of water and triggers the germination process.</div>", "topic": "GROWTH : GERMINATION OF SEEDS AND CONDITION NECESSARY FOR GERMINATION OF SEEDS"}, {"id": "objective>Biology>2009>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The eye defect illustrated is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">myopia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hypermetropia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">astigmatism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cataract</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is called hypermetropia or long-sightedness, Hypermetropia is a condition in which parallel rays of light from close object are brought to focus behind the retina , hence the person can see distance object clearly </div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>2009>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The function of the correcting lens is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">diverge incoming rays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">converge incoming rays </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reflect incoming rays </div>", "<div style=\"font-family:Cambria;font-size:17px;\">screen incoming rays</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The function of the correcting lens is to converge incoming rays.</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>2009>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important ecological factor in a terrestrial environment is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rainfall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">humidity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wind </div>", "<div style=\"font-family:Cambria;font-size:17px;\">soil</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most important ecological factor in a terrestrial environment is soil. Soil is the medium in which plants grow and obtain their nutrients. It also supports many forms of life, including bacteria, fungi, insects, and other organisms, all of which contribute to a habitat's biodiversity and ecological balance.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2009>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The association between bacteria residing in the caecum and the ruminant is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">parasitism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">predation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">saprophytism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mutualism</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The association between bacteria residing in the caecum and the ruminant is mutualism. Mutualism is a type of symbiotic relationship where both organisms benefit. In this case, the bacteria help the ruminant digest cellulose and other complex carbohydrates, and in return, the bacteria get a warm, nutrient-rich environment to live in.</div>", "topic": "ECOLOGY : SYMBIOTIC INTERACTIONS OF PLANTS AND ANIMALS"}, {"id": "objective>Biology>2009>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A marine protozoan is likely to have no contractile vacuole mainly because the cytoplasm is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">isotonic to sea water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hypotonic to sea water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hypertonic to sea water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">impervious to sea water </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A marine protozoan is likely to have no contractile vacuole mainly because the cytoplasm is isotonic to sea water. In biology, isotonic refers to two solutions having the same osmotic pressure across a semipermeable membrane. This state allows for the free movement of water across the membrane without changing the concentration of solutes on either side. In this case, the cytoplasm of the marine protozoan and the sea water have the same concentration of solutes, hence, there is no need for a contractile vacuole to regulate water balance.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2009>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In freshwater marshes and swamps, the most important abiotic factor that organisms have to adapt to is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nature of substratum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high salinity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low pH</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In freshwater marshes and swamps, the substratum (the surface upon which the plants and animals live) is a critical abiotic factor that organisms must adapt to. The substratum can be composed of mud, silt, sand, or other materials, and its characteristics can affect the availability of resources such as water, nutrients, and oxygen.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2009>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following biomass could be characterized by very low rainfall, cold nights, hot days and fast blooming plants?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Northern Guinea savanna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Southern Guinea savanna </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tropical desert</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Montane forest</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The biomass characterized by very low rainfall, cold nights, hot days and fast blooming plants is the Tropical desert. Deserts are characterized by extremely low rainfall, which makes them one of the harshest environments on Earth. The temperature in deserts can vary greatly, with hot days and cold nights. The plants in deserts are adapted to these conditions and often bloom quickly after rainfall.</div>", "topic": "LOCAL(NIGERIAN) BIOMES : DESERT"}, {"id": "objective>Biology>2009>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The zone of physiological stress is represented by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">I and III. The diagram shows the population size of a given species in relation to temperature, divided into three zones: Zone I, Zone II, and Zone III. <br/> Zone of Tolerance: This is where the population thrives, often represented by a peak in the population size. <br/> Zone of Physiological Stress: This is where the population survives but experiences stress, leading to a lower population size. <br/> Zone of Intolerance: This is where the population cannot survive. <br/> From the diagram: <br/> -Zone I: Represents the lower temperature range where the population size is very low, indicating a stressful or intolerant environment. <br/> Zone II: Represents the optimal temperature range where the population size is at its peak. <br/> Zone III: Represents the higher temperature range where the population size decreases again, indicating a stressful or intolerant environment. <br/> Therefore, the zones of physiological stress are represented by Zones I and III, where the population size is low due to suboptimal. </div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2009>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The optimum temperature for the growth of the organism is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">25<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">75<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The optimum temperature for the growth of the organism is 50<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C.</div>", "topic": "GROWTH : MEANING OF GROWTH"}, {"id": "objective>Biology>2009>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Mass of a crucible = 10g  <br/>  Mass of a crucible and soil before heating = 29g  <br/>  Mass of a crucible and soil after heating = 18g  <br/> From the information above, determine the percentage of water in the given soil sample?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">58%</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mass of crucible = 10g <br/> Mc + Ms = 29g (before heating) <br/> Ms = 19g (before heating). <br/>  <br/> Mc + Ms = 18g (after heating) <br/> Ms = 18g - 10g = 8g (after heating) <br/>  <br/> Therefore, the amount of water present in the soil = Mass of soil before heating- Mass of soil after heating.  <br/>  <br/> Mw = 19g - 8g = 11g <br/>  <br/> Percentage of water = (11 ÷ 19) × 100 = 57.9 percent. <br/> </div>", "topic": "SOIL : CHARACTERISTICS OF DIFFERENT TYPES OF SOIL"}, {"id": "objective>Biology>2009>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>I Onchocerciasis  <br/> II Schistosomiasis  <br/>  III Salmonellosis  <br/> IV Meningitis </strong>  <br/>  Which of the diseases listed above are associated with water?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and II only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">II, III and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and IV</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III. Options I and II, Onchocerciasis and Schistosomiasis, are water-related diseases, as they are transmitted through contact with contaminated water. <br/>  <br/> Option III, Salmonellosis, can also be waterborne, as Salmonella bacteria can contaminate water sources, leading to food and water poisoning. <br/>  <br/> I and II only, is incorrect because Salmonellosis (III) can also be waterborne. <br/>  <br/> II, III, and IV, is incorrect because Meningitis (IV) is not typically associated with water. <br/>  <br/> II and IV, is incorrect because Meningitis (IV) is not typically associated with water, and Salmonellosis (III) is also a waterborne disease. <br/>  <br/> Therefore, the correct answer is  I, II, and III, as all three options are associated with water.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2009>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major cause of global warming is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">burning of fossil fuel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">construction of dams</div>", "<div style=\"font-family:Cambria;font-size:17px;\">use of electricity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exploration of space</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The major cause of global warming is the burning of fossil fuels. Fossil fuels like coal, oil, and natural gas, when burned, release carbon dioxide into the atmosphere. Carbon dioxide is a greenhouse gas, which traps heat in the atmosphere and contributes to global warming. Therefore, the correct answer is option 1.</div>", "topic": "HUMANS AND ENVIRONMENT : POLLUTION AND ITS CONTROL"}, {"id": "objective>Biology>2009>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The uniqueness of an individual organism in a population is accounted for by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">evolution </div>", "<div style=\"font-family:Cambria;font-size:17px;\">variation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adaptation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mutation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The uniqueness of an individual organism in a population is accounted for by variation. Variation refers to the differences in physical traits among individuals within a population. These differences may be due to genetic factors, environmental factors, or a combination of both.</div>", "topic": "VARIATION IN POPULATION : APPLICATION OF VARIATION"}, {"id": "objective>Biology>2009>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A phenotypic character with intermediate forms that can be graded from one extreme to the other  is referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">discontinuous variation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">continuous variation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a mutant </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a genome</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A phenotypic character with intermediate forms that can be graded from one extreme to the other is referred to as continuous variation. Continuous variation is a type of genetic variation where individuals in a population vary in small ways from the average phenotype. This variation is often due to the combined effect of multiple genes.</div>", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS"}, {"id": "objective>Biology>2009>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A farmer's assumption that the seed from a good harvest will produce a good yield is explained by the theory of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">evolution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adaptation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">variation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heredity</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A farmer's assumption that the seed from a good harvest will produce a good yield is explained by the theory of heredity. Heredity is the passing on of traits from parents to their offspring; either through asexual reproduction or sexual reproduction. This is the process by which an offspring cell or organism acquires or becomes predisposed to the characteristics of its parent cell or organism.</div>", "topic": "HEREDITY : APPLICATION OF THE PRINCIPLES OF HEREDITY"}, {"id": "objective>Biology>2009>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Mendelian inheritance, discontinuous characters are controlled by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">centrosomes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alleles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chromosomes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chromatids</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Mendelian inheritance, discontinuous characters are controlled by the alleles. Alleles are different forms of a gene that are found at the same place on a chromosome. They control the inheritance of traits.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2009>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A woman with the ability to roll her tongue (Tt) marries a man who cannot roll his tongue (tt). What is the probability of each of their children being a tongue roller?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">100%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">75%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25%</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tt = 2, tt = 2 <br/> Pr(tongue roller ) = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">2</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">4</span> x 100 = 50% <br/> It is 50%. Any of her chromosomes; T or t can be paired with the any of the t's of the male. <br/>  <img src=\"2009/k3.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "HEREDITY : PROBABILITY IN GENETICS AND SEX DETERMINATION"}, {"id": "objective>Biology>2009>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A health condition that is known to have resulted from gene mutation is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Malaria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">colour blindness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sickle-cell anaemia </div>", "<div style=\"font-family:Cambria;font-size:17px;\">anaemia</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sickle-cell anaemia is a health condition that is known to have resulted from gene mutation. It is a genetic disorder that affects the shape and functionality of the red blood cells. The mutation causes the red blood cells to become sickle-shaped, hence the name. This can lead to various complications as these sickle-shaped cells can block blood vessels, preventing blood flow to certain parts of the body.</div>", "topic": "HEREDITY : CHROMOSOMES"}, {"id": "objective>Biology>2009>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Plants grow in an area that is neither too wet nor too dry are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Xerophytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mesophytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Epiphytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrophytes</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mesophytes are plants that grow in an area that is neither too wet nor too dry. They are adapted to well-drained soils with a moderate water supply.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2009>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The part of a domestic fowl responsible for preventing heat loss is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">filoplume</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contour feather</div>", "<div style=\"font-family:Cambria;font-size:17px;\">down feather </div>", "<div style=\"font-family:Cambria;font-size:17px;\">quill</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The down feather of a domestic fowl is responsible for preventing heat loss. Down feathers are fluffy because they lack barbicels, so the barbules float free of each other, allowing the feathers to trap air and provide excellent thermal insulation.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2009>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following animals is most adapted for water conservation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Earthworms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mammals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Flatworms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Insects</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Insects are most adapted for water conservation. They have a waxy cuticle that prevents water loss, and their excretory system is designed to remove waste with minimal water loss. This is a crucial adaptation for survival in various environments, including arid conditions.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2009>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The specialized pigment cells that are involved in colouration and colour change in animals are the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">xanthophyl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chromatophores</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chlorophyll</div>", "<div style=\"font-family:Cambria;font-size:17px;\">melanin</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chromatophores are the specialized pigment cells that are involved in colouration and colour change in animals. They are found in a wide range of animals including amphibians, fish, reptiles, crustaceans and cephalopods. The other options are incorrect as xanthophyl is a yellow pigment found in plants, chlorophyll is a green pigment also found in plants, and melanin is a pigment found in many organisms which is responsible for hair, skin and eye color.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2009>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During the dry season in the tropics, the body metabolism of some animals slows to a minimal level in a process referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hibernation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aestivation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dormancy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">senescense</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During the dry season in the tropics, some animals slow their body metabolism to a minimal level in a process referred to as aestivation. This is a state of animal dormancy, similar to hibernation, characterized by inactivity and a lowered metabolic rate, that is entered in response to high temperatures and arid conditions.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2009>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">According to Darwin, the driving force behind evolutionary change is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">natural selection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">genetic drift</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mutation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gene flow</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Darwin, the driving force behind evolutionary change is natural selection. Natural selection is the differential survival and reproduction of individuals due to differences in phenotype. It is a key mechanism of evolution.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}];
